  ('disabled-7fec267e-moex-00005', 'disabled-7fec267e', 'disabled-7fec267e-moex-114-decd973b', 'sub-disabled-7fec267e-02', NULL, 'single_choice', '依司法院大法官解釋，關於憲法增修條文第4條第2項，依政黨名單投票 選舉產生之立法委員，未獲得百分之五以上政黨選舉票之政黨不得參與席 次分配之規定，下列敘述何者正確？', '["本條文與選舉平等原則有違，有修正之必要", "本條文與權力分立原則有違，有修正之必要", "本條文並未牴觸民主共和國與國民主權原則", "本條文牴觸直接選舉原則，有修正之必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
